INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7d8f8131-e3f7-4919-b49d-ac248db83900',
  '00000000-0000-0000-0000-000000000001',
  $escape$Scala JMH Benchmarking — Avoiding JVM Warm-Up Lies$escape$,
  $escape$Naïve Scala microbenchmarks are almost always wrong. The JVM's JIT compiler aggressively optimizes hot code paths after ~10,000 invocations, meaning your first measurements are measuring interpretation overhead, not steady-state performance. Use JMH (Java Microbenchmark Harness) via the `sbt-jmh` plugin — it handles warm-up iterations, fork isolation, and dead-code elimination prevention automatically.

Key pitfalls specific to Scala: boxing of primitives in generic collections inflates allocation rates (prefer `Array[Int]` over `List[Int]` in hot paths), and lazy vals introduce a `volatile` read on every access after initialization. Use `@Benchmark` with `@BenchmarkMode(Mode.AverageTime)` and always set `@OutputTimeUnit(TimeUnit.NANOSECONDS)` for sub-microsecond work. Run with `-prof gc` to surface allocation pressure — often the real bottleneck isn't CPU but GC pauses from short-lived objects. For profiling production workloads, attach async-profiler via `-agentpath` to get flamegraphs without safepoint bias that JVM's built-in sampling introduces.$escape$,
  $escape$// build.sbt
enablePlugins(JmhPlugin)

import org.openjdk.jmh.annotations._
import java.util.concurrent.TimeUnit

@State(Scope.Thread)
@BenchmarkMode(Array(Mode.AverageTime))
@OutputTimeUnit(TimeUnit.NANOSECONDS)
@Warmup(iterations = 5, time = 1)
@Measurement(iterations = 10, time = 1)
@Fork(2)
class ListVsArrayBench {
  val list: List[Int] = (1 to 1000).toList
  val arr: Array[Int] = (1 to 1000).toArray

  @Benchmark def sumList(): Int = list.sum       // boxes each Int
  @Benchmark def sumArray(): Int = arr.sum       // stays unboxed
}$escape$,
