INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bae0dcf1-4782-4c7a-b07f-d838e741da58',
  '00000000-0000-0000-0000-000000000001',
  $escape$Scala on the JVM — JIT Warmup, Cold Starts, and What GraalVM Native Changes$escape$,
  $escape$Scala compiles to JVM bytecode, not native machine code. At runtime, the JVM interprets bytecode initially, then the JIT compiler (C1 → C2 tiered compilation) profiles hot paths and emits optimized native code. This means Scala services are slow for the first few thousand requests — a real problem in serverless or short-lived container environments.

The JVM's JIT aggressively inlines, devirtualizes, and unrolls loops based on runtime profiling. Scala's heavy use of higher-order functions and trait dispatch benefits enormously from this — a `List.map` chain can be nearly as fast as a hand-written loop after warmup.

For cold-start-sensitive workloads, GraalVM Native Image compiles Scala ahead-of-time to a native binary. Startup drops from ~500ms to ~20ms. The tradeoff: no runtime JIT optimization, reflection must be configured explicitly (`native-image.properties`), and Scala's `ClassTag`/`TypeTag` machinery needs careful handling.

For long-running services (Play, Akka HTTP, http4s), JIT warmup is a non-issue. For AWS Lambda or CLI tools, reach for Native Image or consider Scala CLI with GraalVM.$escape$,
  $escape$// build.sbt — GraalVM Native Image via sbt-native-image
enablePlugins(NativeImagePlugin)

nativeImageOptions ++= List(
  "--no-fallback",
  "--initialize-at-build-time",
  "-H:ReflectionConfigurationFiles=reflect-config.json"
)

// Measure JIT warmup impact in a tight loop
@main def benchmark(): Unit =
  val data = (1 to 1_000_000).toVector
  for i <- 1 to 5 do
    val t0 = System.nanoTime()
    val result = data.foldLeft(0L)(_ + _)
    val elapsed = (System.nanoTime() - t0) / 1_000_000
    println(s"Run $i: ${elapsed}ms, sum=$result")$escape$,
  $escape$kotlin$escape$,
