INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8707d9ae-d2a2-426e-95bd-ec55e594c3dc',
  '00000000-0000-0000-0000-000000000001',
  $escape$Scala Code Quality — Scalafmt, Scalafix, and Enforcing Idiomatic Style$escape$,
  $escape$Scala's flexibility is a double-edged sword — without tooling enforcement, codebases drift into inconsistent, Java-flavored Scala fast. Scalafmt handles formatting; configure it with `version`, `maxColumn = 100`, and `rewrite.rules = [RedundantBraces, SortImports]` in `.scalafmt.conf`. Run `sbt scalafmtAll` in CI to fail on drift.

Scalafix goes deeper. The `DisableSyntax` rule lets you ban `null`, `var`, `throw`, and `isInstanceOf` at the compiler level — the exact constructs that signal un-idiomatic Scala. Pair it with `OrganizeImports` and `RemoveUnused` to eliminate dead code silently accumulating in long-lived services.

For idiom enforcement, `WartRemover` adds a plugin-level gate: `wartremoverWarnings ++= Warts.allBut(Wart.DefaultArguments)` catches `Any`, `asInstanceOf`, mutable collections, and `Return` statements. Prefer `Option` over nullable returns, `Either` over exceptions for expected failures, and `for`-comprehensions over nested `flatMap` chains. Use `final case class` by default — it prevents unintended subclassing and enables exhaustive pattern match checking. These aren't style preferences; they're correctness guarantees the compiler enforces for free.$escape$,
  $escape$// project/plugins.sbt
addSbtPlugin("org.scalameta"  % "sbt-scalafmt" % "2.5.2")
addSbtPlugin("ch.epfl.scala"  % "sbt-scalafix"  % "0.12.1")
addSbtPlugin("org.wartremover" % "sbt-wartremover" % "3.1.6")

// .scalafix.conf
rules = [OrganizeImports, RemoveUnused, DisableSyntax]
DisableSyntax.noNulls = true
DisableSyntax.noVars  = true
DisableSyntax.noThrows = true

// build.sbt
wartremoverWarnings ++= Warts.allBut(
  Wart.DefaultArguments,
  Wart.Nothing
)$escape$,
  $escape$bash$escape$,
